function GiveOpportunity(t){var n=this,i=$("#"+t);this.tabID=t,this.getOpportunity=function(){switch(i.find("[name=selType]").val()){case"3":i.find(".opportunity").show();break;default:i.find(".opportunity").hide()}},this.rebindEl=function(){},this.loadOnReady=function(){i.find("[name=selType]").on("change",function(){n.getOpportunity()}),n.getOpportunity(),n.rebindEl()}}